// Rise 6.0 - handling S40PacketDisconnect for AutoReconnect
if (packet instanceof S40PacketDisconnect) {
    S40PacketDisconnect disconnect = (S40PacketDisconnect) packet;
    String reason = disconnect.getReason().getUnformattedText();

    // Don't reconnect on bans
    if (reason.toLowerCase().contains("banned") ||
        reason.toLowerCase().contains("blacklisted") ||
        reason.toLowerCase().contains("permanently")) {
        return; // let vanilla handle the disconnect
    }

    // Cancel disconnect and reconnect
    event.setCancelled(true);

    // If anti-cheat kick, cycle disabler mode
    if (reason.toLowerCase().contains("watchdog") ||
        reason.toLowerCase().contains("sentinel") ||
        reason.toLowerCase().contains("aac")) {
        Disabler.cycleMode();
    }

    // Reconnect after 3 second delay
    new Thread(() -> {
        try { Thread.sleep(3000); } catch (Exception e) {}
        Minecraft.getMinecraft().addScheduledTask(() -> {
            mc.displayGuiScreen(new GuiConnecting(
                mc.currentScreen != null ? mc.currentScreen : new GuiMainMenu(),
                mc, lastServerData));
        });
    }).start();
}

// Vanilla S40PacketDisconnect definition:
package net.minecraft.network.play.server;

public class S40PacketDisconnect implements Packet<INetHandlerPlayClient> {
    private IChatComponent reason;

    public S40PacketDisconnect() {}
    public S40PacketDisconnect(IChatComponent reasonIn) {
        this.reason = reasonIn;
    }

    public void readPacketData(PacketBuffer buf) throws IOException {
        this.reason = buf.readChatComponent();
    }

    public void processPacket(INetHandlerPlayClient handler) {
        handler.handleDisconnect(this);
    }

    public IChatComponent getReason() {
        return this.reason;
    }
}

